<template><el-card><template #header>知识冲突检测</template><DataTable :data="rows"><el-table-column prop="title" label="冲突标题"/><el-table-column prop="fileA" label="相关文件 A"/><el-table-column prop="fileB" label="相关文件 B"/><el-table-column prop="type" label="冲突类型"/><el-table-column label="风险等级"><template #default="s"><StatusTag :value="s.row.risk"/></template></el-table-column><el-table-column prop="detectedAt" label="检测时间"/><el-table-column prop="status" label="处理状态"/><el-table-column label="操作"><template #default="s"><el-button link type="primary" @click="detail=s.row">详情</el-button><el-button link @click="s.row.status='已处理'">标记处理</el-button></template></el-table-column></DataTable><DetailDrawer v-model="open" title="冲突详情"><el-descriptions border :column="1"><el-descriptions-item label="文件 A 口径">容量阈值按旧版执行。</el-descriptions-item><el-descriptions-item label="文件 B 口径">容量阈值按修订版执行。</el-descriptions-item><el-descriptions-item label="AI 判断说明">新版本发布时间更晚且层级更高。</el-descriptions-item><el-descriptions-item label="处理建议">废止旧切片，更新规则依据。</el-descriptions-item><el-descriptions-item label="专家处理意见"><el-input type="textarea" v-model="detail.opinion"/></el-descriptions-item></el-descriptions></DetailDrawer></el-card></template>
<script setup lang="ts">import { computed, ref } from 'vue'; import { conflicts } from '@/mock/data'; import DataTable from '@/components/DataTable.vue'; import DetailDrawer from '@/components/DetailDrawer.vue'; import StatusTag from '@/components/StatusTag.vue'; const rows=ref<any[]>(JSON.parse(JSON.stringify(conflicts))); const detail=ref<any>(); const open=computed({get:()=>!!detail.value,set:v=>{if(!v)detail.value=null}});</script>
